mapper.select:
	SELECT COUNT(*)
    FROM REPORT R


            R.STATUS = #{reportStatus}



            AND R.TARGET_TYPE = #{targetType}

SELECT * FROM ( SELECT ROWNUM RNUM, A.* FROM (
SELECT R.REPORT_NO as reportNo, R.TARGET_TYPE as targetType, R.TARGET_NO as targetNo, C.REPORT_CATEGORY as reportCategoryName, M.USER_ID as reporterId, R.CREATED_AT as createdAt, R.STATUS as status FROM REPORT R LEFT JOIN REPORT_CATEGORY C ON R.REPORT_CD_NO = C.REPORT_CATEGORY_NO LEFT JOIN MEMBER M ON R.USER_NO = M.USER_NO
R.STATUS = #{reportStatus}
AND R.TARGET_TYPE = #{targetType}
ORDER BY R.REPORT_NO DESC
) A ) WHERE RNUM BETWEEN #{offset} AND #{limit}

