SELECT COUNT(*)
FROM FAQ


        STATUS = #{status}

SELECT * FROM ( SELECT ROWNUM RNUM, A.* FROM ( SELECT F.FAQ_ID as faqId, F.TITLE as title, F.STATUS as status, F.CREATE_DATE as createDate, M.USER_ID as userId FROM FAQ F JOIN MEMBER M ON F.USER_NO = M.USER_NO
F.STATUS = #{status}
ORDER BY F.CREATE_DATE DESC ) A ) WHERE RNUM BETWEEN #{offset} AND #{limit}

SELECT *
FROM FAQ_IMG
WHERE FAQ_ID = #{faqId}

SELECT * FROM ( SELECT ROWNUM RNUM, A.* FROM ( SELECT I.ITEM_NO, C.ITEM_CATEGORY AS categoryName, I.ITEM_TITLE, M.USER_ID AS userId, I.START_PRICE, I.CURRENT_PRICE, I.START_TIME, I.END_TIME, I.STATUS, I.CREATE_AT, (SELECT COUNT(*) FROM BID B WHERE B.ITEM_NO = I.ITEM_NO) AS bidCount, (SELECT IMG_URL FROM ITEM_IMG WHERE ITEM_NO = I.ITEM_NO AND ROWNUM = 1) AS mainImg FROM ITEM I JOIN MEMBER M ON (I.USER_NO = M.USER_NO) JOIN ITEM_CD C ON (I.ITEM_CD_NO = C.ITEM_CATEGORY_NO) WHERE I.STATUS = 'N'
AND I.ITEM_TITLE LIKE '%' || #{searchKeyword} || '%'
ORDER BY I.ITEM_NO DESC ) A ) WHERE RNUM BETWEEN #{offset} AND #{limit}

